"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import maplibregl, { Map as MLMap, ScaleControl } from "maplibre-gl";
import "maplibre-gl/dist/maplibre-gl.css";
import { BASEMAPS, type Basemap } from "@/lib/basemaps";
import { useSettings } from "@/lib/settings";
import { getAccessToken } from "@/lib/sentinel/auth";
import { fetchLatestOverlay } from "@/lib/sentinel/latest-overlay";
import type { Bbox, Credentials } from "@/types/sentinel";
import { SearchBox } from "./SearchBox";
import type { GeocodeResult } from "@/lib/geocode";
import { gibsDateNDaysAgo, gibsTileUrl, type GibsLayer } from "@/lib/gibs";

const CLOUDS_DAYS_BACK = 7;
const CLOUDS_ANIM_INTERVAL_MS = 900;
const CLOUDS_COMPOSITE_LAYERS: GibsLayer[] = [
  "VIIRS_SNPP_CorrectedReflectance_TrueColor",
];

const OVERLAY_SOURCE_ID = "latest-overlay";
const OVERLAY_LAYER_ID = "latest-overlay-layer";
const WEATHER_SOURCE_ID = "weather";
const WEATHER_LAYER_ID = "weather-layer";
const MIN_FETCH_ZOOM = 8;

interface ViewState {
  center: [number, number];
  zoom: number;
}

type Projection = "mercator" | "globe";

interface OverlayState {
  url: string;
  bbox: Bbox;
  from: string;
  to: string;
  opacity: number;
}

type FetchState =
  | { kind: "idle" }
  | { kind: "loading" }
  | { kind: "error"; message: string };

interface Props {
  credentials: Credentials | null;
}

function rasterStyle(basemap: Basemap) {
  return {
    version: 8 as const,
    sources: {
      base: {
        type: "raster" as const,
        tiles: [basemap.url],
        tileSize: basemap.tileSize ?? 256,
        attribution: basemap.attribution,
        maxzoom: basemap.maxzoom ?? 18,
      },
    },
    layers: [{ id: "base", type: "raster" as const, source: "base" }],
  };
}

function applyBasemap(map: MLMap, basemap: Basemap) {
  if (basemap.kind === "raster") {
    map.setStyle(rasterStyle(basemap));
  } else {
    map.setStyle(basemap.url);
  }
}

const WEATHER_MAXZOOM = 7;

function ensureWeatherLayer(map: MLMap, urls: string[], opacity: number) {
  if (map.getLayer(WEATHER_LAYER_ID)) return;
  if (map.getSource(WEATHER_SOURCE_ID)) map.removeSource(WEATHER_SOURCE_ID);
  map.addSource(WEATHER_SOURCE_ID, {
    type: "raster",
    tiles: urls,
    tileSize: 256,
    maxzoom: WEATHER_MAXZOOM,
    attribution:
      '<a href="https://earthdata.nasa.gov/gibs" target="_blank" rel="noreferrer">NASA GIBS</a>',
  });
  map.addLayer({
    id: WEATHER_LAYER_ID,
    type: "raster",
    source: WEATHER_SOURCE_ID,
    maxzoom: 8,
    paint: { "raster-opacity": opacity, "raster-fade-duration": 0 },
  });
}

function updateWeatherTiles(map: MLMap, urls: string[]) {
  const source = map.getSource(WEATHER_SOURCE_ID) as unknown as
    | { setTiles?: (tiles: string[]) => void }
    | undefined;
  if (source?.setTiles) source.setTiles(urls);
}

function updateWeatherOpacity(map: MLMap, opacity: number) {
  if (map.getLayer(WEATHER_LAYER_ID)) {
    map.setPaintProperty(WEATHER_LAYER_ID, "raster-opacity", opacity);
  }
}

function removeWeatherLayer(map: MLMap) {
  if (map.getLayer(WEATHER_LAYER_ID)) map.removeLayer(WEATHER_LAYER_ID);
  if (map.getSource(WEATHER_SOURCE_ID)) map.removeSource(WEATHER_SOURCE_ID);
}

function addOverlay(map: MLMap, url: string, bbox: Bbox, opacity: number) {
  const [west, south, east, north] = bbox;
  const coordinates: [number, number][] = [
    [west, north],
    [east, north],
    [east, south],
    [west, south],
  ];

  if (map.getLayer(OVERLAY_LAYER_ID)) map.removeLayer(OVERLAY_LAYER_ID);
  if (map.getSource(OVERLAY_SOURCE_ID)) map.removeSource(OVERLAY_SOURCE_ID);

  map.addSource(OVERLAY_SOURCE_ID, { type: "image", url, coordinates });
  map.addLayer({
    id: OVERLAY_LAYER_ID,
    type: "raster",
    source: OVERLAY_SOURCE_ID,
    paint: { "raster-opacity": opacity, "raster-fade-duration": 0 },
  });
}

function removeOverlay(map: MLMap) {
  if (map.getLayer(OVERLAY_LAYER_ID)) map.removeLayer(OVERLAY_LAYER_ID);
  if (map.getSource(OVERLAY_SOURCE_ID)) map.removeSource(OVERLAY_SOURCE_ID);
}

export function LiveMap({ credentials }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<MLMap | null>(null);
  const {
    basemapId: active,
    projection,
    weatherOn,
    weatherOpacity,
    setBasemapId: setActive,
    setProjection,
    setWeatherOn,
    setWeatherOpacity,
  } = useSettings();
  const [view, setView] = useState<ViewState>({
    center: [6.775, 51.2277],
    zoom: 12,
  });
  const [overlay, setOverlay] = useState<OverlayState | null>(null);
  const [weatherFrameIndex, setWeatherFrameIndex] = useState(CLOUDS_DAYS_BACK - 1);
  const [weatherPlaying, setWeatherPlaying] = useState(false);
  const [weatherLoading, setWeatherLoading] = useState(false);
  const [fetchState, setFetchState] = useState<FetchState>({ kind: "idle" });

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return;

    const initial = BASEMAPS.find((b) => b.id === active) ?? BASEMAPS[0];
    const map = new maplibregl.Map({
      container: containerRef.current,
      style: initial.kind === "raster" ? rasterStyle(initial) : initial.url,
      center: view.center,
      zoom: view.zoom,
      minZoom: 2,
      maxZoom: 18,
      attributionControl: { compact: true },
      hash: true,
    });
    mapRef.current = map;
    map.once("load", () => map.setProjection({ type: projection }));

    map.addControl(new maplibregl.NavigationControl({ showCompass: true }), "top-right");
    map.addControl(new ScaleControl({ maxWidth: 120, unit: "metric" }), "bottom-left");
    map.addControl(new maplibregl.FullscreenControl(), "top-right");
    map.addControl(new maplibregl.GeolocateControl({ trackUserLocation: false }), "top-right");

    map.on("moveend", () => {
      const c = map.getCenter();
      setView({ center: [c.lng, c.lat], zoom: map.getZoom() });
    });

    map.on("error", (e) => {
      const msg = e?.error?.message ?? "";
      if (
        msg.includes("Failed to fetch") ||
        msg.includes("AJAXError") ||
        msg.includes("reading 'signal'") ||
        msg.includes("aborted")
      ) {
        return;
      }
      console.warn("[map]", e.error);
    });

    if (process.env.NODE_ENV !== "production") {
      (window as unknown as { __map: MLMap }).__map = map;
    }

    const resizeObserver = new ResizeObserver(() => map.resize());
    resizeObserver.observe(containerRef.current);

    return () => {
      resizeObserver.disconnect();
      map.remove();
      mapRef.current = null;
    };
  }, []);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;
    const basemap = BASEMAPS.find((b) => b.id === active);
    if (!basemap) return;
    applyBasemap(map, basemap);

    const reapply = () => {
      map.setProjection({ type: projection });
      if (overlay) addOverlay(map, overlay.url, overlay.bbox, overlay.opacity);
    };
    if (map.isStyleLoaded()) {
      setTimeout(reapply, 0);
    } else {
      map.once("load", reapply);
    }
  }, [active]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;
    const apply = () => {
      try {
        map.setProjection({ type: projection });
      } catch {
        // style not yet loaded
      }
    };
    apply();
    map.on("style.load", apply);
    return () => {
      map.off("style.load", apply);
    };
  }, [projection]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map || !overlay) return;
    if (map.getLayer(OVERLAY_LAYER_ID)) {
      map.setPaintProperty(OVERLAY_LAYER_ID, "raster-opacity", overlay.opacity);
    }
  }, [overlay?.opacity]);

  useEffect(() => {
    if (!weatherOn) {
      const map = mapRef.current;
      if (map) removeWeatherLayer(map);
      setWeatherLoading(false);
    }
  }, [weatherOn]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map || !weatherOn) return;
    const onSourceData = (e: maplibregl.MapSourceDataEvent) => {
      if (e.sourceId !== WEATHER_SOURCE_ID) return;
      const src = map.getSource(WEATHER_SOURCE_ID);
      if (!src) return;
      setWeatherLoading(!map.isSourceLoaded(WEATHER_SOURCE_ID));
    };
    map.on("sourcedata", onSourceData);
    map.on("sourcedataloading", onSourceData);
    return () => {
      map.off("sourcedata", onSourceData);
      map.off("sourcedataloading", onSourceData);
    };
  }, [weatherOn]);

  interface WeatherFrame {
    time: number;
    date: string;
    urls: string[];
  }

  const weatherFrames: WeatherFrame[] = (() => {
    const all: WeatherFrame[] = [];
    for (let i = CLOUDS_DAYS_BACK; i >= 1; i -= 1) {
      const date = gibsDateNDaysAgo(i);
      all.push({
        time: Date.parse(date) / 1000,
        date,
        urls: CLOUDS_COMPOSITE_LAYERS.map((layer) => gibsTileUrl({ layer, date })),
      });
    }
    return all;
  })();

  useEffect(() => {
    if (!weatherOn || !weatherPlaying || weatherFrames.length === 0) return;
    const id = setInterval(() => {
      setWeatherFrameIndex((i) => (i + 1) % weatherFrames.length);
    }, CLOUDS_ANIM_INTERVAL_MS);
    return () => clearInterval(id);
  }, [weatherOn, weatherPlaying, weatherFrames.length]);

  const currentWeatherUrls = weatherFrames[weatherFrameIndex]?.urls;
  const weatherUrlsKey = currentWeatherUrls?.join("|") ?? "";

  useEffect(() => {
    const map = mapRef.current;
    if (!map || !weatherOn || !currentWeatherUrls) return;
    const apply = () => {
      ensureWeatherLayer(map, currentWeatherUrls, weatherOpacity);
      updateWeatherTiles(map, currentWeatherUrls);
    };
    if (map.isStyleLoaded()) {
      apply();
    } else {
      map.once("style.load", apply);
    }
    map.on("style.load", apply);
    return () => map.off("style.load", apply);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [weatherOn, active, weatherUrlsKey]);

  useEffect(() => {
    const map = mapRef.current;
    if (!map || !weatherOn) return;
    updateWeatherOpacity(map, weatherOpacity);
  }, [weatherOn, weatherOpacity]);

  const handleFetchLatest = useCallback(async () => {
    const map = mapRef.current;
    if (!map || !credentials) return;
    if (map.getZoom() < MIN_FETCH_ZOOM) {
      setFetchState({
        kind: "error",
        message: `Zoom in to at least z${MIN_FETCH_ZOOM} before fetching`,
      });
      return;
    }

    setFetchState({ kind: "loading" });
    try {
      const bounds = map.getBounds();
      const bbox: Bbox = [
        bounds.getWest(),
        bounds.getSouth(),
        bounds.getEast(),
        bounds.getNorth(),
      ];
      const token = await getAccessToken(credentials);
      const result = await fetchLatestOverlay({
        bbox,
        accessToken: token,
        daysBack: 14,
        maxPixelsPerSide: 2048,
      });
      const url = URL.createObjectURL(result.blob);

      setOverlay((prev) => {
        if (prev) URL.revokeObjectURL(prev.url);
        return { url, bbox: result.bbox, from: result.from, to: result.to, opacity: 1 };
      });
      addOverlay(map, url, result.bbox, 1);
      setFetchState({ kind: "idle" });
    } catch (err) {
      setFetchState({
        kind: "error",
        message: err instanceof Error ? err.message : String(err),
      });
    }
  }, [credentials]);

  function handleClearOverlay() {
    const map = mapRef.current;
    if (!map) return;
    removeOverlay(map);
    setOverlay((prev) => {
      if (prev) URL.revokeObjectURL(prev.url);
      return null;
    });
    setFetchState({ kind: "idle" });
  }

  function handleOpacityChange(opacity: number) {
    setOverlay((prev) => (prev ? { ...prev, opacity } : prev));
  }

  function handleGeocodeSelect(result: GeocodeResult) {
    const map = mapRef.current;
    if (!map) return;
    if (result.extent) {
      const [west, north, east, south] = result.extent;
      map.fitBounds(
        [
          [west, south],
          [east, north],
        ],
        { padding: 60, duration: 900, maxZoom: 15 },
      );
    } else {
      const cat = result.category;
      let zoom = 14;
      if (cat === "city" || cat === "town") zoom = 12;
      else if (cat === "village" || cat === "suburb") zoom = 13;
      else if (cat === "country") zoom = 5;
      else if (cat === "state" || cat === "region") zoom = 7;
      else if (cat === "house" || cat === "building") zoom = 17;
      map.flyTo({ center: result.coordinates, zoom, duration: 900 });
    }
  }

  const activeBm = BASEMAPS.find((b) => b.id === active);
  const canFetch = credentials !== null && view.zoom >= MIN_FETCH_ZOOM;

  return (
    <div className="relative h-full w-full">
      <div ref={containerRef} className="h-full w-full" />

      <div className="pointer-events-none absolute left-3 top-3 z-10 flex flex-col gap-2">
        <SearchBox onSelect={handleGeocodeSelect} />

        <div className="pointer-events-auto rounded-xl border border-neutral-700 bg-neutral-900/85 p-2 text-xs text-neutral-200 shadow-xl backdrop-blur">
          <div className="mb-1.5 px-1 text-[10px] font-semibold uppercase tracking-wider text-neutral-500">
            Basemap
          </div>
          <div className="flex flex-col gap-1">
            {BASEMAPS.map((b) => (
              <button
                key={b.id}
                type="button"
                onClick={() => setActive(b.id)}
                className={`rounded-lg px-2.5 py-1.5 text-left transition-colors ${
                  active === b.id
                    ? "bg-sky-500/20 text-sky-200 ring-1 ring-inset ring-sky-500/50"
                    : "text-neutral-300 hover:bg-neutral-800"
                }`}
              >
                {b.label}
              </button>
            ))}
          </div>
        </div>

        <div className="pointer-events-auto flex items-center gap-1.5 rounded-lg border border-neutral-700 bg-neutral-900/85 px-2 py-1.5 font-mono text-[11px] text-neutral-400 shadow backdrop-blur">
          <span>
            {view.center[1].toFixed(4)}°, {view.center[0].toFixed(4)}° · z
            {view.zoom.toFixed(1)}
          </span>
          <span className="mx-1 h-3 w-px bg-neutral-700" aria-hidden />
          <ProjectionToggle
            active={projection}
            onChange={setProjection}
          />
        </div>

        <div className="pointer-events-auto flex flex-col items-stretch gap-2 rounded-xl border border-neutral-700 bg-neutral-900/85 p-2 text-xs shadow-xl backdrop-blur">
          <div className="px-1 text-[10px] font-semibold uppercase tracking-wider text-neutral-500">
            Latest imagery
          </div>
          <button
            type="button"
            onClick={handleFetchLatest}
            disabled={!canFetch || fetchState.kind === "loading"}
            className="rounded-lg bg-sky-500 px-3 py-1.5 font-medium text-black hover:bg-sky-400 disabled:cursor-not-allowed disabled:bg-neutral-700 disabled:text-neutral-400"
          >
            {fetchState.kind === "loading"
              ? "Fetching…"
              : overlay
                ? "Refresh overlay"
                : "Fetch for this view"}
          </button>
          {!credentials && (
            <p className="max-w-[180px] text-[11px] text-neutral-400">
              Add credentials in the header to enable live fetches.
            </p>
          )}
          {credentials && view.zoom < MIN_FETCH_ZOOM && (
            <p className="max-w-[180px] text-[11px] text-amber-400">
              Zoom in to z{MIN_FETCH_ZOOM} or closer
            </p>
          )}
          {fetchState.kind === "error" && (
            <p className="max-w-[220px] break-words text-[11px] text-red-400">
              {fetchState.message}
            </p>
          )}
          {overlay && (
            <>
              <div className="flex items-center gap-2 pt-1">
                <span className="text-[10px] uppercase text-neutral-500">Opacity</span>
                <input
                  type="range"
                  min={0}
                  max={1}
                  step={0.05}
                  value={overlay.opacity}
                  onChange={(e) => handleOpacityChange(Number(e.target.value))}
                  className="w-24 accent-sky-400"
                />
                <span className="w-8 text-right text-[10px] text-neutral-400">
                  {Math.round(overlay.opacity * 100)}%
                </span>
              </div>
              <div className="text-[10px] text-neutral-500">last 14 days · live data</div>
              <button
                type="button"
                onClick={handleClearOverlay}
                className="rounded-lg border border-neutral-700 px-3 py-1 text-neutral-300 hover:bg-neutral-800"
              >
                Clear overlay
              </button>
            </>
          )}
        </div>

        <WeatherPanel
          enabled={weatherOn}
          onToggle={setWeatherOn}
          frames={weatherFrames}
          frameIndex={weatherFrameIndex}
          onFrameIndex={setWeatherFrameIndex}
          isPlaying={weatherPlaying}
          onPlayingChange={setWeatherPlaying}
          opacity={weatherOpacity}
          onOpacityChange={setWeatherOpacity}
          loading={weatherLoading}
        />
      </div>
    </div>
  );
}

interface WeatherPanelProps {
  enabled: boolean;
  onToggle: (on: boolean) => void;
  frames: { time: number; date: string; urls: string[] }[];
  frameIndex: number;
  onFrameIndex: (i: number) => void;
  isPlaying: boolean;
  onPlayingChange: (p: boolean) => void;
  opacity: number;
  onOpacityChange: (o: number) => void;
  loading: boolean;
}

function WeatherPanel({
  enabled,
  onToggle,
  frames,
  frameIndex,
  onFrameIndex,
  isPlaying,
  onPlayingChange,
  opacity,
  onOpacityChange,
  loading,
}: WeatherPanelProps) {
  const currentFrame = frames[frameIndex];

  return (
    <div className="pointer-events-auto flex flex-col items-stretch gap-2 rounded-xl border border-neutral-700 bg-neutral-900/85 p-2 text-xs shadow-xl backdrop-blur">
      <div className="flex items-center justify-between">
        <span className="flex items-center gap-1.5 px-1 text-[10px] font-semibold uppercase tracking-wider text-neutral-500">
          Clouds
          {loading && enabled && (
            <span className="inline-block h-2 w-2 animate-pulse rounded-full bg-sky-400" aria-label="Loading tiles" />
          )}
        </span>
        <PillToggle enabled={enabled} onToggle={() => onToggle(!enabled)} />
      </div>

      {enabled && frames.length > 0 && currentFrame && (
        <>
          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={() => onPlayingChange(!isPlaying)}
              className="flex h-6 w-6 items-center justify-center rounded-md border border-neutral-700 text-neutral-300 hover:bg-neutral-800"
              aria-label={isPlaying ? "Pause" : "Play"}
            >
              {isPlaying ? (
                <svg viewBox="0 0 10 10" className="h-2.5 w-2.5" fill="currentColor">
                  <rect x="1.5" y="1" width="2" height="8" />
                  <rect x="6.5" y="1" width="2" height="8" />
                </svg>
              ) : (
                <svg viewBox="0 0 10 10" className="h-2.5 w-2.5" fill="currentColor">
                  <path d="M2 1 L9 5 L2 9 Z" />
                </svg>
              )}
            </button>
            <input
              type="range"
              min={0}
              max={frames.length - 1}
              step={1}
              value={frameIndex}
              onChange={(e) => {
                onPlayingChange(false);
                onFrameIndex(Number(e.target.value));
              }}
              className="flex-1 accent-sky-400"
            />
          </div>

          <div className="flex items-center justify-between text-[10px]">
            <span className="text-neutral-400">
              {new Date(currentFrame.time * 1000).toLocaleDateString([], {
                year: "numeric",
                month: "short",
                day: "numeric",
              })}
            </span>
            <span className="text-neutral-500">
              {frameIndex + 1}/{frames.length}
            </span>
          </div>

          <div className="flex items-center gap-2">
            <span className="text-[10px] uppercase text-neutral-500">Opacity</span>
            <input
              type="range"
              min={0}
              max={1}
              step={0.05}
              value={opacity}
              onChange={(e) => onOpacityChange(Number(e.target.value))}
              className="w-24 accent-sky-400"
            />
            <span className="w-8 text-right text-[10px] text-neutral-400">
              {Math.round(opacity * 100)}%
            </span>
          </div>

          <div className="text-[10px] text-neutral-500">
            NASA GIBS · VIIRS SNPP true-color · daily
          </div>
        </>
      )}
    </div>
  );
}

function PillToggle({
  enabled,
  onToggle,
}: {
  enabled: boolean;
  onToggle: () => void;
}) {
  return (
    <button
      type="button"
      onClick={onToggle}
      className={`relative h-5 w-9 rounded-full transition-colors ${enabled ? "bg-sky-500" : "bg-neutral-700"}`}
      aria-label="Toggle weather"
    >
      <span
        className={`absolute top-0.5 h-4 w-4 rounded-full bg-white shadow transition-[left] ${
          enabled ? "left-[18px]" : "left-0.5"
        }`}
      />
    </button>
  );
}

function ProjectionToggle({
  active,
  onChange,
}: {
  active: Projection;
  onChange: (p: Projection) => void;
}) {
  return (
    <div className="flex overflow-hidden rounded-md border border-neutral-700">
      <button
        type="button"
        onClick={() => onChange("mercator")}
        title="Flat (Mercator)"
        aria-label="Flat projection"
        className={`flex h-5 w-5 items-center justify-center transition-colors ${
          active === "mercator"
            ? "bg-sky-500/25 text-sky-200"
            : "text-neutral-400 hover:text-neutral-200"
        }`}
      >
        <svg viewBox="0 0 16 16" className="h-3 w-3" fill="none" stroke="currentColor" strokeWidth="1.5">
          <rect x="2" y="3.5" width="12" height="9" rx="1" />
          <path d="M2 8h12M6 3.5v9M10 3.5v9" />
        </svg>
      </button>
      <button
        type="button"
        onClick={() => onChange("globe")}
        title="Globe (sphere)"
        aria-label="Globe projection"
        className={`flex h-5 w-5 items-center justify-center transition-colors ${
          active === "globe"
            ? "bg-sky-500/25 text-sky-200"
            : "text-neutral-400 hover:text-neutral-200"
        }`}
      >
        <svg viewBox="0 0 16 16" className="h-3 w-3" fill="none" stroke="currentColor" strokeWidth="1.5">
          <circle cx="8" cy="8" r="5.5" />
          <ellipse cx="8" cy="8" rx="2.5" ry="5.5" />
          <path d="M2.5 8h11" />
        </svg>
      </button>
    </div>
  );
}
